#!/bin/bash
set -e
echo "📝 feedbackController.ts 最終修正版を適用..."
echo "" | base64 -d > backend/src/controllers/feedbackController.ts

echo "🔍 backend コンパイルチェック..."
cd backend && npx tsc --noEmit 2>&1 | tee /tmp/tsc_final.log
ERRS=$(grep -c "error TS" /tmp/tsc_final.log 2>/dev/null || echo 0)
cd ..

echo "Backend エラー数: $ERRS"

if [ "$ERRS" -eq 0 ]; then
    echo "✅ エラー0件 — Push実行"
    git add backend/src/controllers/feedbackController.ts
    git commit -m "fix: feedbackController noUncheckedIndexedAccess 対応 完全修正"
    git push origin main
    echo "🎉 Push完了!"
else
    grep "error TS" /tmp/tsc_final.log
fi
